class Solution:
    def maxDepthAfterSplit(self, seq: str) -> List[int]:
        a, b, res = 0, 0, []
        for c in seq:
            if c == '(':
                if a <= b:
                    a += 1
                    res.append(0)
                else:
                    b += 1
                    res.append(1)
            else:
                if a > b:
                    a -= 1
                    res.append(0)
                else:
                    b -= 1
                    res.append(1)
        return res
```
